// This helper function is dedicated to making text safe for Telegram's MarkdownV2.
// It escapes specific characters that Telegram reserves for formatting.
function escapeMarkdownV2(text) {
  if (typeof text !== 'string') {
    return '';
  }
  // The characters to escape are: _ * [ ] ( ) ~ ` > # + - = | { } . !
  // Note: We are NOT escaping the backslash `\` itself, as we use it for escaping.
  // We use a regular expression to find any of these characters and prepend a `\` to them.
  const charsToEscape = /[_*\[\]()~`>#+\-=|{}.!]/g;
  return text.replace(charsToEscape, '\\$&');
}

// --- Main Execution Logic ---

// 1. Get the AI's generated message from the previous node's output.
// The AI Agent node places its final text response in the 'output' property.
const aiGeneratedMessage = $json.output;

// 2. Get the chat_id from the initial trigger of this workflow.
const initialContext = $items("Start")[0].json;
const chatId = initialContext.chat_id;

// 3. Escape the AI-generated message to make it safe for Telegram.
// This is the crucial step to prevent formatting errors.
const safeMessageForTelegram = escapeMarkdownV2(aiGeneratedMessage);

// 4. Return the final data in the standard format that the main
//    'Kirana_Agent_Conv' workflow is expecting.
return [{
  json: {
    // This is the message that will be sent to the user.
    confirmation_message: safeMessageForTelegram,

    // This is the user's ID, so the message goes to the right person.
    chat_id: chatId
  }
}];
